class Solution(object):
    def bstFromPreorder(self, preorder):
        def build(lower, upper, idx):
            if idx[0] >= len(preorder):
                return None
            val = preorder[idx[0]]
            if val < lower or val > upper:
                return None
            idx[0] += 1
            node = TreeNode(val)
            node.left = build(lower, val, idx)
            node.right = build(val, upper, idx)
            return node
        return build(float('-inf'), float('inf'), [0])
